#include <bits/stdc++.h>
using namespace std;

const int N=5e5+5,mod=1e9+7;

int n,g[N][2],mi[N];
char s[N];
long long ans;

int Hash(int l,int r,int tp){
    if(!tp)
        return (g[r][0]+mod-1LL*g[l-1][0]*mi[r-l+1]%mod)%mod;
    else
        return (g[l][1]+mod-1LL*g[r+1][1]*mi[r-l+1]%mod)%mod;
}

int main(){
    scanf("%d%s",&n,s+1);
    mi[0]=1;
    for(int i=1;i<=n;i++)
        g[i][0]=(g[i-1][0]*2+s[i]-'0')%mod,mi[i]=mi[i-1]*2%mod;
    for(int i=n;i;i--)
        g[i][1]=(g[i+1][1]*2+1-(s[i]-'0'))%mod;
    for(int i=1;i<n;i++){
        int l=0,r=min(i,n-i);
        while(l<r){
            int mid=l+r+1>>1;
            if(Hash(i-mid+1,i,0)==Hash(i+1,i+mid,1))
                l=mid;
            else
                r=mid-1;
        }
        ans+=l;
    }
    printf("%lld",ans);
    return 0;
}
